// Name: Miku_LuoTianyi
// ID: miku_luotianyi

class MikuLuotianyi {
    constructor(runtime) {
        this.runtime = runtime;
        this.luotianyi = 'data:image/png;base64,';
        this.miku = 'data:image/png;base64,';
        this.audio = 'data:audio/mpeg;base64,';
    }
    getInfo() {
        return {
            id: 'mikuluotianyi',
            name: 'Miku_LuoTianyi',
            color1: '#66ccff',
            color2: '#48aee1',
            color3: '#2a90c3',
            blocks: [
                {
                    opcode: 'luotianyia',
                    blockType: 'command',
                    text: '[ICON]我是初音未来',
                    arguments: {
                        ICON: {
                            type: Scratch.ArgumentType.IMAGE,
                            dataURI: this.luotianyi,
                            alt: '洛天依',
                            flipRTL: false
                        }
                    }
                },
                {
                    opcode: 'mikua',
                    blockType: 'command',
                    text: '[ICON]这才是洛天依',
                    arguments: {
                        ICON: {
                            type: Scratch.ArgumentType.IMAGE,
                            dataURI: this.miku,
                            alt: '洛天依',
                            flipRTL: false
                        }
                    }
                }
            ]
        }

    }
    playAudio() {
        const audio = new Audio(this.audio);

        audio.addEventListener('canplaythrough', () => {
            audio.play().catch(e => {
                console.error('播放失败:', e);
            });
        });

        audio.addEventListener('error', (e) => {
            console.error('音频加载错误:', e);
        });

        return audio;
    }

    start() {
        this.playAudio(); // 只调用一次
    }

    luotianyia(args) {
        this.start();
    }

    mikua(args) {
        this.start();
    }




}

Scratch.extensions.register(new MikuLuotianyi());
